Patching the snake motion to animate between grid squares.
_____javascript
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .board {
              position: relative;
              width: 320px;
              height: 320px;
              background: #111;
              overflow: hidden;
            }
            .cell {
              position: absolute;
              width: 32px;
              height: 32px;
              box-sizing: border-box;
            }
            .snake {
              background: #4ade80;
              border-radius: 6px;
              transition: transform 140ms linear;
              will-change: transform;
            }
            .snake.head {
              background: #22c55e;
            }
            .food {
              background: #f97316;
              border-radius: 50%;
            }
          </style>
          <div class="board" id="board"></div>
        `

        const board = parent.querySelector("#board")
        const size = 10
        const cell = 32
        const render = (snake, food) => {
          board.innerHTML = ""
          snake.forEach((seg, i) => {
            const d = document.createElement("div")
            d.className = `cell snake ${i === 0 ? "head" : ""}`
            d.style.transform = `translate(${seg.x * cell}px, ${seg.y * cell}px)`
            board.appendChild(d)
          })
          const f = document.createElement("div")
          f.className = "cell food"
          f.style.transform = `translate(${food.x * cell}px, ${food.y * cell}px)`
          board.appendChild(f)
        }

        let snake = [{ x: 4, y: 4 }, { x: 3, y: 4 }, { x: 2, y: 4 }]
        let food = { x: 7, y: 4 }
        let dir = { x: 1, y: 0 }
        let nextDir = dir

        const placeFood = () => {
          food = { x: Math.floor(Math.random() * size), y: Math.floor(Math.random() * size) }
        }

        window.addEventListener("keydown", (e) => {
          const map = {
            ArrowUp: { x: 0, y: -1 },
            ArrowDown: { x: 0, y: 1 },
            ArrowLeft: { x: -1, y: 0 },
            ArrowRight: { x: 1, y: 0 },
          }
          const nd = map[e.key]
          if (!nd) return
          if (nd.x === -dir.x && nd.y === -dir.y) return
          nextDir = nd
        })

        const step = () => {
          dir = nextDir
          const head = snake[0]
          const nh = { x: (head.x + dir.x + size) % size, y: (head.y + dir.y + size) % size }
          snake = [nh, ...snake]
          if (nh.x === food.x && nh.y === food.y) {
            placeFood()
          } else {
            snake.pop()
          }
          render(snake, food)
        }

        render(snake, food)
        placeFood()
        render(snake, food)
        setInterval(step, 140)
      }
    }
  ]
})

