                const x = i % 16
                const y = Math.floor(i / 16)
                const snake = [
                  [7, 6], [6, 6], [5, 6], [5, 7], [5, 8]
                ]
                const head = snake[0]
                const food = [11, 4]
                const cls =
                  (x === head[0] && y === head[1]) ? "cell head" :
                  snake.some(([sx, sy]) => sx === x && sy === y) ? "cell snake" :
                  (x === food[0] && y === food[1]) ? "cell food" : "cell"
                return `<div class="${cls}"></div>`
              }).join("")}
            </div>
          </div>
        </div>
